#include <stdio.h>
#include <string.h>
#include <stdlib.h>

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    char buffer[100005];
    while (T--) {
        scanf("%s", buffer);
        int n = strlen(buffer);
        char *out = (char*)malloc(n + 1);
        int i = 0, j = 0;
        while (i < n) {
            if (i + 5 <= n && strncmp(buffer + i, "party", 5) == 0) {
                memcpy(out + j, "pawri", 5);
                i += 5;
                j += 5;
            } else {
                out[j++] = buffer[i++];
            }
        }
        out[j] = '\0';
        printf("%s\n", out);
        free(out);
    }
    return 0;
}

