#!/usr/bin/env python3
import sys

def solve():
    data = sys.stdin.read().splitlines()
    if not data:
        return
    t = int(data[0])
    out_lines = []
    for i in range(1, t + 1):
        s = data[i].strip()
        res = []
        idx = 0
        n = len(s)
        while idx < n:
            if idx + 5 <= n and s[idx:idx+5] == "party":
                res.append("pawri")
                idx += 5
            else:
                res.append(s[idx])
                idx += 1
        out_lines.append(''.join(res))
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    solve()

